-- FocusTime Seed Data (소규모: 유저 100명, 세션 500개)
-- Generated for MySQL (focustime database)
-- Run: mysql -u root -p focustime < seed.sql

USE focustime;
SET SQL_SAFE_UPDATES = 0;
SET FOREIGN_KEY_CHECKS = 0;
SET NAMES utf8mb4;

DELETE FROM `session_videos`;
DELETE FROM `session_messages`;
DELETE FROM `session_goals`;
DELETE FROM `session_participants`;
DELETE FROM `favorites`;
DELETE FROM `notifications`;
DELETE FROM `notification_settings`;
DELETE FROM `payments`;
DELETE FROM `subscriptions`;
DELETE FROM `refresh_tokens`;
DELETE FROM `password_resets`;
DELETE FROM `oauth_tokens`;
DELETE FROM `blocks`;
DELETE FROM `reports`;
DELETE FROM `sessions`;
DELETE FROM `users`;

-- ==================== USERS ====================

-- ==================== SUBSCRIPTIONS ====================

-- ==================== SESSIONS ====================

-- ==================== SESSION_PARTICIPANTS ====================

-- ==================== SESSION_GOALS ====================

-- ==================== FAVORITES ====================

-- ==================== NOTIFICATIONS ====================

-- ==================== NOTIFICATION_SETTINGS ====================

-- ==================== BLOCKS ====================

-- ==================== REPORTS ====================

SET FOREIGN_KEY_CHECKS = 1;

-- ==================== VERIFY ====================
SELECT 'users' AS tbl, COUNT(*) AS cnt FROM users
UNION ALL SELECT 'sessions', COUNT(*) FROM sessions
UNION ALL SELECT 'session_participants', COUNT(*) FROM session_participants
UNION ALL SELECT 'session_goals', COUNT(*) FROM session_goals
UNION ALL SELECT 'favorites', COUNT(*) FROM favorites
UNION ALL SELECT 'notifications', COUNT(*) FROM notifications
UNION ALL SELECT 'subscriptions', COUNT(*) FROM subscriptions
UNION ALL SELECT 'blocks', COUNT(*) FROM blocks
UNION ALL SELECT 'reports', COUNT(*) FROM reports;
SET SQL_SAFE_UPDATES = 1;

commit;
